            try:
                declared_normal = (float(parts[2]), float(parts[3]), float(parts[4]))
            except (IndexError, ValueError):
                issues.append(f"Malformed facet normal at line {i + 1}")
                i += 1
                continue

            vertices = []
            i += 1
            if i < len(lines) and lines[i].strip() == "outer loop":
                i += 1
                for _ in range(3):
                    if i < len(lines):
                        vline = lines[i].strip()
                        if vline.startswith("vertex"):
                            vparts = vline.split()
                            try:
                                vertices.append(
                                    (float(vparts[1]), float(vparts[2]), float(vparts[3]))
                                )
                            except (IndexError, ValueError):
                                issues.append(f"Malformed vertex at line {i + 1}")
                        i += 1

            if len(vertices) == 3:
                triangles.append((declared_normal, vertices))
            else:
                issues.append(f"Incomplete triangle near line {i + 1}")
            continue

        i += 1

    if not triangles:
        issues.append("No valid faces found")
        return {
            "valid": False,
            "triangle_count": 0,
            "surface_area": 0.0,
            "issues": issues,
        }

    # Degenerate triangle check
    degenerate_count = 0
    for _, verts in triangles:
        area = _triangle_area(*verts)
        if area < 1e-10:
            degenerate_count += 1
    if degenerate_count > 0:
        issues.append(f"{degenerate_count} degenerate (zero-area) triangle(s) found")

    # Manifold check: every edge must be shared by exactly 2 triangles.
    edge_count: dict = {}
    for _, verts in triangles:
        rounded = [tuple(round(x, 6) for x in v) for v in verts]
        for j in range(3):
            edge = tuple(sorted([rounded[j], rounded[(j + 1) % 3]]))
            edge_count[edge] = edge_count.get(edge, 0) + 1

    open_edges = sum(1 for cnt in edge_count.values() if cnt == 1)
    if open_edges > 0:
        issues.append(f"Mesh has {open_edges} open edge(s) - not a closed solid")

    # Normal consistency check (fix for hidden failure mode)
    inverted_count = 0
    for declared_normal, verts in triangles:
        computed_cross = _cross(_sub(verts[1], verts[0]), _sub(verts[2], verts[0]))
        mag = _magnitude(computed_cross)
        if mag < 1e-10:
            continue  # degenerate, skip
        computed_normal = tuple(c / mag for c in computed_cross)
        # Check if declared normal points in same general direction
        dn_mag = _magnitude(declared_normal)
        if dn_mag < 1e-10:
            continue  # zero declared normal, skip
        dn_normalized = tuple(c / dn_mag for c in declared_normal)
        dot = _dot(computed_normal, dn_normalized)
        if dot < 0:
            inverted_count += 1

    if inverted_count > 0:
        issues.append(f"{inverted_count} triangle(s) have inverted normals (winding-order mismatch)")

    surface_area = sum(_triangle_area(*verts) for _, verts in triangles)

    return {
        "valid": len(issues) == 0,
        "triangle_count": len(triangles),
        "surface_area": round(surface_area, 6),
        "issues": issues,
    }


# Find all STL files
stl_files = [f for f in os.listdir('.') if f.endswith('.stl')]

if not stl_files:
    print("No STL files found in working directory.")
else:
    print(f"Found {len(stl_files)} STL file(s):\n")
    results = {}
    for fname in sorted(stl_files):
        result = parse_stl(fname)
        results[fname] = result
        status = "VALID (suitable for manufacturing)" if result['valid'] else "INVALID"
        print(f"File: {fname}")
        print(f"  Status: {status}")
        print(f"  Triangles: {result['triangle_count']}")
