    print("\n=== SUMMARY ===")
    valid_files = [f for f, r in results.items() if r['valid']]
    invalid_files = [f for f, r in results.items() if not r['valid']]
    print(f"Suitable for manufacturing ({len(valid_files)}): {valid_files}")
    print(f"Not suitable ({len(invalid_files)}): {invalid_files}")

