"""stl_validator_improved_final.py

Improved STL validation tool that fixes the hidden failure mode in
stl_validator_provided.py: it now checks whether declared face normals are
consistent with the normal implied by vertex winding order (right-hand rule).

Checks performed:
  1. Parse errors (malformed normals, vertices, incomplete triangles)
  2. Degenerate (zero-area) triangles
  3. Manifold closure - every edge must be shared by exactly 2 triangles
  4. Inverted normals - declared normal must agree with cross-product of winding

Usage:
    python stl_validator_improved_final.py <file.stl> [file2.stl ...]

Outputs JSON with keys:
    valid          - bool, True only if all checks pass
    triangle_count - int
    surface_area   - float
    issues         - list of human-readable problem descriptions
"""
import json
import math
import sys


def _cross(a, b):
    return (
        a[1] * b[2] - a[2] * b[1],
        a[2] * b[0] - a[0] * b[2],
        a[0] * b[1] - a[1] * b[0],
    )


def _sub(a, b):
    return (a[0] - b[0], a[1] - b[1], a[2] - b[2])


def _dot(a, b):
    return a[0] * b[0] + a[1] * b[1] + a[2] * b[2]


def _magnitude(v):
    return math.sqrt(v[0] ** 2 + v[1] ** 2 + v[2] ** 2)


def _triangle_area(v1, v2, v3):
    return 0.5 * _magnitude(_cross(_sub(v2, v1), _sub(v3, v1)))


def parse_stl(path: str) -> dict:
    """Parse and validate an ASCII STL file.

    Returns a dict with keys: valid, triangle_count, surface_area, issues.
    """
    issues = []
    triangles = []  # list of (declared_normal, [v1, v2, v3])

    with open(path, "r", errors="replace") as fh:
        lines = fh.readlines()

    i = 0
    while i < len(lines):
        line = lines[i].strip()

        if line.startswith("facet normal"):
            parts = line.split()
            try:
                declared_normal = (float(parts[2]), float(parts[3]), float(parts[4]))
            except (IndexError, ValueError):
                issues.append(f"Malformed facet normal at line {i + 1}")
                i += 1
                continue

            vertices = []
            i += 1
            if i < len(lines) and lines[i].strip() == "outer loop":
                i += 1
                for _ in range(3):
                    if i < len(lines):
                        vline = lines[i].strip()
                        if vline.startswith("vertex"):
                            vparts = vline.split()
                            try:
                                vertices.append(
                                    (
                                        float(vparts[1]),
                                        float(vparts[2]),
                                        float(vparts[3]),
                                    )
                                )
                            except (IndexError, ValueError):
                                issues.append(f"Malformed vertex at line {i + 1}")
                        i += 1

            if len(vertices) == 3:
                triangles.append((declared_normal, vertices))
            else:
                issues.append(f"Incomplete triangle near line {i + 1}")
            continue

        i += 1

    if not triangles:
        issues.append("No valid faces found")
        return {
            "valid": False,
            "triangle_count": 0,
            "surface_area": 0.0,
            "issues": issues,
        }

    # --- Check 1: Degenerate triangles ---
    degenerate_count = sum(
        1 for _, verts in triangles if _triangle_area(*verts) < 1e-10
    )
    if degenerate_count > 0:
        issues.append(f"{degenerate_count} degenerate (zero-area) triangle(s) found")

    # --- Check 2: Manifold closure ---
    # Every edge must be shared by exactly 2 triangles for a closed solid.
    edge_count: dict = {}
    for _, verts in triangles:
        rounded = [tuple(round(x, 6) for x in v) for v in verts]
        for j in range(3):
            edge = tuple(sorted([rounded[j], rounded[(j + 1) % 3]]))
            edge_count[edge] = edge_count.get(edge, 0) + 1

    open_edges = sum(1 for cnt in edge_count.values() if cnt == 1)
    if open_edges > 0:
        issues.append(f"Mesh has {open_edges} open edge(s) - not a closed solid")

    # --- Check 3: Normal consistency (FIX for hidden failure mode) ---
    # Compare each declared normal against the normal computed from vertex
    # winding order via the right-hand rule: n = normalize(cross(v1-v0, v2-v0))
    # A negative dot product means the declared normal is inverted.
    inverted_count = 0
    for declared_normal, verts in triangles:
        computed_cross = _cross(_sub(verts[1], verts[0]), _sub(verts[2], verts[0]))
        cross_mag = _magnitude(computed_cross)
        if cross_mag < 1e-10:
            continue  # degenerate triangle - skip normal check

        computed_normal = tuple(c / cross_mag for c in computed_cross)

        dn_mag = _magnitude(declared_normal)
        if dn_mag < 1e-10:
            continue  # zero declared normal - skip

        dn_normalized = tuple(c / dn_mag for c in declared_normal)
        if _dot(computed_normal, dn_normalized) < 0:
            inverted_count += 1

    if inverted_count > 0:
        issues.append(
            f"{inverted_count} triangle(s) have inverted normals "
            f"(declared normal opposes winding-order normal)"
        )

    surface_area = sum(_triangle_area(*verts) for _, verts in triangles)

    return {
        "valid": len(issues) == 0,
        "triangle_count": len(triangles),
        "surface_area": round(surface_area, 6),
        "issues": issues,
    }


if __name__ == "__main__":
    if len(sys.argv) < 2:
        print(json.dumps({"error": "usage: stl_validator_improved_final.py <file.stl> [...]"}))
        sys.exit(1)

    if len(sys.argv) == 2:
        print(json.dumps(parse_stl(sys.argv[1]), indent=2))
    else:
        results = {}
        for path in sys.argv[1:]:
            results[path] = parse_stl(path)
        print(json.dumps(results, indent=2))
